SELECT activity_description
FROM lifecycle_activities
WHERE module_id = 1;

SELECT ROUND(impact_per_unit, 2) AS rounded_impact
FROM lifecycle_activities
WHERE activity_id = 0;

SELECT module_id, COUNT(activity_id) AS activity_count
FROM activity_modules
GROUP BY module_id;

SELECT product_id, COUNT(activity_id) AS total_activities
FROM lifecycle_activities
GROUP BY product_id;

SELECT geo_mean AS max_geometric_mean, activity_description
FROM lifecycle_activities
WHERE activity_id = 0;
